function o(r,e=!1){if(e){if(r>=1e8)return`$${(r/1e8).toFixed(1)}M`;if(r>=1e5)return`$${(r/1e5).toFixed(0)}K`}return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(r/100)}function a(r){if(r<60)return`${Math.round(r)}m`;const e=Math.floor(r/60),t=Math.round(r%60);return`${e}h ${t}m`}function n(r){return r.replace(/_/g," ").replace(/\b\w/g,e=>e.toUpperCase())}export{n as a,o as b,a as f};
